rules.pseudocode:
max_dist = grid_width + grid_height - 2
for each action a in available_actions:
  if a == 'eat':
    if food_at_agent_position:
      a_imm = 1.0
      a_abs = 2.0 * (food.palatability - 0.1) / 0.9 - 1.0
    else:
      a_imm = 0.0; a_abs = 0.0
  elif a == 'stay':
    a_imm = 0.0; a_abs = 0.0
  else:  # movement
    next_pos = position + direction_delta(a)
    nearest = find_nearest_food(next_pos, food_list)
    if nearest:
      dist = manhattan_distance(next_pos, nearest)
      a_imm = 1.0 - dist / max_dist
      a_abs = 2.0 * (nearest.palatability - 0.1) / 0.9 - 1.0
    else:
      a_imm = 0.0; a_abs = 0.0
